import type { FolderSuggestion } from "@/types/folder"

type SuggestionsListProps = {
  suggestions: FolderSuggestion[]
}

/**
 * Lists organization recommendations generated by analysis.
 */
export function SuggestionsList({ suggestions }: SuggestionsListProps) {
  if (suggestions.length === 0) {
    return (
      <div className="rounded-lg border border-border bg-background p-4">
        <p className="font-medium">No suggestions yet</p>
        <p className="mt-1 text-sm text-muted-foreground">
          This folder structure looks clean based on the current V1 rules.
        </p>
      </div>
    )
  }

  return (
    <div className="space-y-3">
      {suggestions.map((suggestion) => (
        <article
          key={suggestion.id}
          className="rounded-lg border border-border bg-background p-4">
          <div className="flex items-start justify-between gap-4">
            <div>
              <p className="text-sm font-medium uppercase text-muted-foreground">
                {suggestion.type}
              </p>

              <h3 className="mt-1 font-semibold">{suggestion.to}</h3>
            </div>

            <span className="rounded-full bg-muted px-2.5 py-1 text-xs font-medium text-muted-foreground">
              {suggestion.confidence}%
            </span>
          </div>

          <p className="mt-3 text-sm text-muted-foreground">
            {suggestion.reason}
          </p>

          {suggestion.from.length > 0 && (
            <div className="mt-3">
              <p className="text-xs font-medium uppercase text-muted-foreground">
                From
              </p>

              <div className="mt-2 flex flex-wrap gap-2">
                {suggestion.from.map((path) => (
                  <span
                    key={path}
                    className="rounded-full border border-border px-2.5 py-1 text-xs text-muted-foreground">
                    {path}
                  </span>
                ))}
              </div>
            </div>
          )}
        </article>
      ))}
    </div>
  )
}
